package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases – новые edge‑case‑тесты для метода
// Order.CalculateTotal().  Они не пересекаются с уже существующими
// TestUnitOrderCalculateTotal*, TestUnitOrderCalculateTotalMixedPrices и т.п.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	t.Run("MixedZeroAndPositivePrices", func(t *testing.T) {
		o := &Order{
			Items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: 0},      // бесплатный товар
				{ProductID: 2, Quantity: 3, Price: 199.99}, // обычный товар
				{ProductID: 3, Quantity: 1, Price: 0},      // ещё один бесплатный
			},
		}
		o.CalculateTotal()
		// 2*0 + 3*199.99 + 1*0 = 599.97
		const want = 599.97
		if math.Abs(o.Total-want) > 1e-9 {
			t.Fatalf("unexpected total, want %v, got %v", want, o.Total)
		}
	})

	t.Run("LargeQuantityAndPrice", func(t *testing.T) {
		// 1 000 000 000 шт. по цене 1 000 000.00 → 1e15 (в пределах float64)
		o := &Order{
			Items: []OrderItem{
				{ProductID: 42, Quantity: 1_000_000_000, Price: 1_000_000.00},
			},
		}
		o.CalculateTotal()
		const want = 1e15 // 1 000 000 000 * 1 000 000.00
		if math.Abs(o.Total-want) > 1e3 { // небольшая погрешность допустима
			t.Fatalf("unexpected total for huge numbers, want %v, got %v", want, o.Total)
		}
	})

	t.Run("NaNPricePropagation", func(t *testing.T) {
		o := &Order{
			Items: []OrderItem{
				{ProductID: 7, Quantity: 1, Price: math.NaN()},
				{ProductID: 8, Quantity: 5, Price: 10.0},
			},
		}
		o.CalculateTotal()
		if !math.IsNaN(o.Total) {
			t.Fatalf("expected total to be NaN when any item price is NaN, got %v", o.Total)
		}
	})

	t.Run("NegativePriceSum", func(t *testing.T) {
		// Валидация продукта/заказа не вызывается в CalculateTotal,
		// поэтому отрицательная цена просто суммируется.
		o := &Order{
			Items: []OrderItem{
				{ProductID: 11, Quantity: 2, Price: -50.0},
				{ProductID: 12, Quantity: 3, Price: 120.0},
			},
		}
		o.CalculateTotal()
		// 2*(-50) + 3*120 = -100 + 360 = 260
		const want = 260.0
		if math.Abs(o.Total-want) > 1e-9 {
			t.Fatalf("unexpected total with negative price, want %v, got %v", want, o.Total)
		}
	})

	t.Run("ZeroQuantityIgnored", func(t *testing.T) {
		// Quantity == 0 – валидатор бы отреагировал, но CalculateTotal
		// просто умножает, поэтому результат 0*price = 0.
		o := &Order{
			Items: []OrderItem{
				{ProductID: 21, Quantity: 0, Price: 999.99},
				{ProductID: 22, Quantity: 5, Price: 20.0},
			},
		}
		o.CalculateTotal()
		// 0*999.99 + 5*20 = 100
		const want = 100.0
		if math.Abs(o.Total-want) > 1e-9 {
			t.Fatalf("unexpected total with zero quantity, want %v, got %v", want, o.Total)
		}
	})
}
```

### Что покрывает тест

| Sub‑test | Что проверяется |
|----------|-----------------|
| **MixedZeroAndPositivePrices** | Суммирование, когда часть товаров имеет цену `0`. |
| **LargeQuantityAndPrice** | Корректность расчёта при очень больших количествах и ценах (проверка, что не происходит переполнения `float64`). |
| **NaNPricePropagation** | Если хотя бы один элемент имеет `Price = NaN`, итоговая сумма тоже должна стать `NaN`. |
| **NegativePriceSum** | `CalculateTotal` не делает валидацию цены – отрицательная цена просто участвует в сумме. |
| **ZeroQuantityIgnored** | При `Quantity = 0` умножение даёт `0`; проверяем, что остальные позиции считаются правильно. |

Эти кейсы **не дублируют** уже существующие тесты (`TestUnitOrderCalculateTotal*`, `TestUnitOrderCalculateTotalMixedPrices`, `TestUnitOrderCalculateTotalNilItems` и т.д.), а расширяют покрытие граничных и «необычных» ситуаций, которые могут возникнуть в реальном коде.

