// TestUnitOrderCalculateTotalEdgeCases adds a few *new* edge‑case scenarios for
// Order.CalculateTotal().  The existing suite already checks empty/nil slices,
// normal‑size orders, float‑precision quirks and that the Total field is
// overwritten.  Here we verify behaviour when:
//
//   1. All items have a price of 0 (the total must be 0).
//   2. Items contain a negative price – the method is a pure sum, so the
//      negative value must be reflected in the result.\n
//   3. Very large quantity × price values that are still representable by a
//      float64 (no overflow, but we check the exact expected total).\n
//   4. A mix of zero‑price and positive‑price items – the zero‑price items
//      must not affect the sum.\n
//   5. An extreme quantity that would overflow an int on 32‑bit platforms –
//      we use int64‑compatible values and verify the calculation works.\n
//
// The test is table‑driven and uses a tolerance when comparing floating‑point
// results (the same approach as TestUnitOrderCalculateTotalFloatPrecision).\n
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	const eps = 1e-9 // tolerance for floating‑point comparison

	tests := []struct {
		name     string
		items    []OrderItem
		expected float64
	}{
		{
			name: "ZeroPriceItems",
			items: []OrderItem{
				{ProductID: 1, Quantity: 5, Price: 0},
				{ProductID: 2, Quantity: 3, Price: 0},
			},
			expected: 0,
		},
		{
			name: "NegativePriceItems",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: -150.0},
				{ProductID: 2, Quantity: 1, Price: 200.0},
			},
			// (-150 * 2) + (200 * 1) = -100
			expected: -100.0,
		},
		{
			name: "LargeQuantityAndPrice",
			items: []OrderItem{
				// 1 000 000 000 × 9 999.99 = 9.99999e+12
				{ProductID: 1, Quantity: 1_000_000_000, Price: 9_999.99},
			},
			expected: 9_999_990_000_000.0,
		},
		{
			name: "MixedZeroAndPositive",
			items: []OrderItem{
				{ProductID: 1, Quantity: 4, Price: 0},
				{ProductID: 2, Quantity: 2, Price: 123.45},
				{ProductID: 3, Quantity: 1, Price: 0},
			},
			// (2 * 123.45) = 246.90
			expected: 246.90,
		},
		{
			name: "QuantityOverflowSafe",
			// int on a 32‑bit build would overflow, but Go’s int is at least
			// 32 bits; we use a value that fits in int64 and verify the sum.
			items: []OrderItem{
				{ProductID: 1, Quantity: int(^uint(0) >> 1), Price: 1.0}, // max int
			},
			// total = maxInt * 1.0
			expected: float64(int(^uint(0) >> 1)),
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			o := Order{
				Items: tt.items,
			}
			o.CalculateTotal()

			if math.Abs(o.Total-tt.expected) > eps {
				t.Fatalf("unexpected total: got %v, want %v", o.Total, tt.expected)
			}

			// Ensure CalculateTotal does not mutate the Items slice (the
			// method is supposed to be a pure calculation).
			if len(o.Items) != len(tt.items) {
				t.Fatalf("items slice length changed: got %d, want %d", len(o.Items), len(tt.items))
			}
			for i := range o.Items {
				if o.Items[i] != tt.items[i] {
