	completeURL := ts.URL + path.Join("/orders", strconv.FormatInt(orderCreated.ID, 10), "complete")
	_ = postJSON(t, completeURL, nil, http.StatusOK)

	// Verify the final status
	getAfterComplete := getJSON(t, ts.URL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10), http.StatusOK)
	var orderAfterComplete struct {
		Status string `json:"status"`
	}
	require.NoError(t, json.NewDecoder(bytes.NewReader(getAfterComplete)).Decode(&orderAfterComplete))
	require.Equal(t, "completed", orderAfterComplete.Status, "order must be 'completed' after Complete")
}

// ---------------------------------------------------------------------------
// Small HTTP helpers used by the test suite (identical to the ones described
// in the project documentation).  They keep the test code tidy and make the
// assertions on status codes explicit.
// ---------------------------------------------------------------------------
func postJSON(t *testing.T, url string, payload any, wantStatus int) []byte {
	var body []byte
	if payload != nil {
		var err error
		body, err = json.Marshal(payload)
		require.NoError(t, err)
	}
	req, err := http.NewRequest(http.MethodPost, url, bytes.NewReader(body))
	require.NoError(t, err)
	req.Header.Set("Content-Type", "application/json")
	resp, err := http.DefaultClient.Do(req)
	require.NoError(t, err)
	defer resp.Body.Close()
	require.Equal(t, wantStatus, resp.StatusCode, "unexpected HTTP status for POST %s", url)
	respBody, err := io.ReadAll(resp.Body)
	require.NoError(t, err)
	return respBody
}

func getJSON(t *testing.T, url string, wantStatus int) []byte {
	resp, err := http.Get(url)
	require.NoError(t, err)
	defer resp.Body.Close()
	require.Equal(t, wantStatus, resp.StatusCode, "unexpected HTTP status for GET %s", url)
	b, err := io.ReadAll(resp.Body)
	require.NoError(t, err)
	return b
}
